constexpr int ZERO_LOC = 21;
constexpr int INITIAL_PHASE = 18;
constexpr int LEFT_TIP_PHASE = 7;

// Right-side zig-zag tip phase for each block
inline int right_phase(char block) {
    switch (block) {
        case 'D': return 21;
        case 'E': return 29;
        case 'F': return 23;
        case 'G': return 4;
        case 'H': return 0;
        case 'I': return 16;
        case 'J': return 22;
        case 'K': return 8;
        case 'L': return 7;
        default: return -1;
    }
}

// Phase update: new_phase = (8 - right_phase(block) + old_phase) % 30
inline int next_phase(int phase, char block) {
    return ((8 - right_phase(block) + phase) % 30 + 30) % 30;
}

// Left-side phase change (period 3, used for A/B leftward joining)
// A: identity. B: 0→2, 1→0, 2→1
inline int left_phase_change(char block, int phase) {
    if (block == 'A') return phase;
    // block == 'B'
    constexpr int table[] = {2, 0, 1};
    return table[phase];
}

