inline const std::vector<int>& get_block_row(char block, int row) {
    switch (block) {
        case 'A': return block_A(row);
        case 'B': return block_B(row);
        case 'C': return block_C(row);
        case 'D': return block_D(row);
        case 'E': return block_E(row);
        case 'F': return block_F(row);
        case 'G': return block_G(row);
        case 'H': return block_H(row);
        case 'I': return block_I(row);
        case 'J': return block_J(row);
        case 'K': return block_K(row);
        case 'L': return block_L(row);
        default: { static const std::vector<int> empty; return empty; }
    }
}

